// Format AI memory daily digest for Telegram. Parses single-row aggregates
// from previous Postgres node and degrades gracefully on empty results.
// Voyage cost estimate: ~chars/4 tokens × $0.02 / 1M tokens (voyage-3.5-lite).
const row = $input.first()?.json ?? {};

const toNum = (v) => Number(v ?? 0);
const total24h = toNum(row.total_24h);
const activeUsers24h = toNum(row.active_users_24h);
const totalChars24h = toNum(row.total_chars_24h);
const total7d = toNum(row.total_7d);
const lifetimeTotal = toNum(row.lifetime_total);
const lifetimeUsers = toNum(row.lifetime_users);

// by_source from json_agg may arrive as array, JSON string, or null.
let bySource = row.by_source ?? [];
if (typeof bySource === 'string') {
  try { bySource = JSON.parse(bySource); } catch { bySource = []; }
}
if (!Array.isArray(bySource)) bySource = [];

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toLocaleDateString('uk-UA', {
  day: 'numeric',
  month: 'long',
  timeZone: 'Europe/Kyiv',
});

// Voyage cost estimate (rough): ~4 chars/token × $0.02 / 1M tokens.
const tokens = Math.round(totalChars24h / 4);
const costUsd = (tokens / 1_000_000) * 0.02;
const costStr = costUsd < 0.01 ? '< $0.01' : `$${costUsd.toFixed(4)}`;

const sourceLines = bySource.length
  ? bySource
      .map((s) => `  • \`${s.source}\`: ${s.cnt} (${s.users} 👤)`)
      .join('\n')
  : '  _— нічого нового за добу —_';

const empty = total24h === 0;
const headline = empty
  ? `🧠 *AI Memory — ${dateStr}*\n\n_За добу нічого не записано._`
  : `🧠 *AI Memory — ${dateStr}*\n\n📦 *${total24h}* memories · 👥 *${activeUsers24h}* юзерів · 💸 ${costStr}`;

const body = empty
  ? ''
  : `\n\n*По джерелах:*\n${sourceLines}\n\n*Lifetime:* ${lifetimeTotal} memories від ${lifetimeUsers} юзерів · *7d:* ${total7d}`;

const footer = `\n\n_Sergeant · ai\\_memories · pgvector_`;

return [{ json: { text: headline + body + footer, total24h, activeUsers24h, empty } }];

// ADR-0038, Wave 3 §3.2 — pre-Telegram step that builds a stable
// `alertId` so n8n retries no-op via ON CONFLICT DO NOTHING server-side.
const item = $input.first()?.json ?? {};
const alertId = `${$workflow.id || 'wf30'}:${$execution.id || 'unknown'}:ai-memory-digest`;
const total24h = Number(item.total24h) || 0;
const activeUsers = Number(item.activeUsers24h) || 0;
const summary = total24h === 0
  ? 'AI memory daily digest — no memories in last 24h.'
  : `AI memory daily — ${total24h} memories from ${activeUsers} users in 24h.`;
return [{
  json: {
    alertId,
    summary,
    text: item.text,
    metadata: {
      workflowId: $workflow.id || 'unknown',
      executionId: $execution.id || 'unknown',
      total24h,
      activeUsers24h: activeUsers,
      lifetimeTotal: Number(item.lifetimeTotal) || 0,
      empty: total24h === 0,
    },
  },
}];
